const d = new Date();
d.setDate(d.getDate() - 2);
const dd = String(d.getDate()).padStart(2, '0');
const mm = String(d.getMonth() + 1).padStart(2, '0');
const yyyy = d.getFullYear();
const sinceYmd = `${yyyy}${mm}${dd}`;

if (!/^\d{8}$/.test(sinceYmd)) {
  node.error('sinceYmd inválido: ' + sinceYmd, msg);
  return null;
}

msg.query = `
  SELECT
    id_movimiento, numero_ingreso, patente, camion, chofer, transporte,
    razon_social, id_caniero, codfinca, sector,
    peso_bruto, tara, neto_cana, trash,
    fecha_entrada, hora_entrada,
    fecha_pesada, hora_pesada,                                                                                     fechaindustrial, estado, mesa, observaciones                                                                 FROM pr_ezi_movimientos
  WHERE (fecha_salida IS NULL OR fecha_salida = '')
    AND fecha_entrada IS NOT NULL
    AND LEN(fecha_entrada) >= 10
    AND (SUBSTRING(fecha_entrada,7,4)
       + SUBSTRING(fecha_entrada,4,2)
       + SUBSTRING(fecha_entrada,1,2)) >= '${sinceYmd}';
  `;
return msg;

const parseDate = (s) => {
  if (!s || typeof s !== 'string') return null;
  const m = s.match(/^(\d{2})\/(\d{2})\/(\d{4})/);
  return m ? `${m[3]}-${m[2]}-${m[1]}` : null;
};

const parseDateTime = (d, h) => {
  const dt = parseDate(d);
  if (!dt) return null;
  let hh = (h && typeof h === 'string' && h.trim() !== '') ? h.trim() : '00:00:00';
  if (/^\d{2}:\d{2}$/.test(hh)) hh += ':00';
  if (!/^\d{2}:\d{2}:\d{2}$/.test(hh)) return null;
  return `${dt} ${hh}`;
};

const rows = Array.isArray(msg.payload) ? msg.payload : [];

const snapshot = rows.map(r => ({
  id_movimiento:    r.id_movimiento,
  numero_ingreso:   r.numero_ingreso,
  patente:          r.patente,
  camion:           r.camion,
  chofer:           r.chofer,
  transporte:       r.transporte,
  caniero_razon:    r.razon_social,
  caniero_id:       r.id_caniero || null,
  codigo_finca:     r.codfinca,
  sector:           r.sector,
  variedad:         null,
  peso_bruto:       r.peso_bruto,
  tara:             r.tara,
  neto_cana:        r.neto_cana,
  trash:            r.trash,
  entrada_at:       parseDateTime(r.fecha_entrada, r.hora_entrada),
  pesada_at:        parseDateTime(r.fecha_pesada,  r.hora_pesada),
  fecha_industrial: parseDate(r.fechaindustrial),
  estado:           r.estado,
  mesa:             r.mesa,
  observaciones:    r.observaciones
}));

flow.set('snapshot_json', JSON.stringify(snapshot));
flow.set('snapshot_count', snapshot.length);
msg.query = 'TRUNCATE production.canchon_snapshot;';
msg.params = [];
return msg;

const json = flow.get('snapshot_json');
const count = flow.get('snapshot_count');
if (!json || count === 0) {
  node.status({fill:'yellow', shape:'ring', text:'0 camiones (TRUNCATE-only)'});
  return null;
}
msg.query = `
INSERT INTO production.canchon_snapshot (
