FROM json_populate_recordset(NULL::production.canchon_snapshot, $1::json);
`;
msg.params = [json];
return msg;

const row = msg.payload && msg.payload[0];
if (!row) { node.warn('sync deshabilitado'); return null; }
const lastId = Number(row.last_id) || 0;
